// mm/src/api/downloadDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';
import { getAccessToken } from '../utils/auth';

const API_BASE =
  process.env.REACT_APP_API_BASE_URL || 'https://manuscriptmagic.fowkes.xyz/services';

/** -----------------------------
 * Helpers: filename + extensions
 * ---------------------------- */

function extFromContentType(ct = '') {
  const t = String(ct).toLowerCase();
  if (t.includes('pdf')) return '.pdf';
  if (t.includes('msword')) return '.doc';
  if (t.includes('officedocument.wordprocessingml')) return '.docx';
  if (t.includes('text/plain')) return '.txt';
  if (t.includes('text/markdown')) return '.md';
  if (t.includes('application/zip')) return '.zip'; // docx is zip-based container
  return '';
}



function getFilenameFromContentDisposition(cd = '') {
  const v = String(cd || '');
  if (!v) return '';

  // filename*=UTF-8''x%20y.docx
  const mStar = v.match(/filename\*\s*=\s*([^;]+)/i);
  if (mStar) {
    const raw = mStar[1].trim().replace(/^UTF-8''/i, '').replace(/^"|"$/g, '');
    try {
      return decodeURIComponent(raw);
    } catch {
      return raw;
    }
  }

  // filename="x.docx"
  const m = v.match(/filename\s*=\s*([^;]+)/i);
  if (m) return m[1].trim().replace(/^"|"$/g, '');

  return '';
}

/** -----------------------------
 * Helpers: blob sniffing
 * ---------------------------- */

function u8ToAscii(u8) {
  return Array.from(u8)
    .map((b) => (b >= 32 && b <= 126 ? String.fromCharCode(b) : ''))
    .join('');
}

function sniffFromBytes(u8) {
  const head = u8ToAscii(u8.slice(0, 16));
  const headLower = head.toLowerCase();

  // PDF: "%PDF"
  if (head.startsWith('%PDF')) return { kind: 'pdf', ext: '.pdf', mime: 'application/pdf' };

  // ZIP: "PK\x03\x04" (DOCX is a ZIP container)
  if (u8.length >= 4 && u8[0] === 0x50 && u8[1] === 0x4b && u8[2] === 0x03 && u8[3] === 0x04) {
    return { kind: 'zip', ext: '.zip', mime: 'application/zip' };
  }

  // HTML
  if (headLower.includes('<!do') || headLower.includes('<html') || headLower.includes('<head')) {
    return { kind: 'html', ext: '.html', mime: 'text/html' };
  }

  // JSON
  const trimmed = u8ToAscii(u8).trim();
  const first = trimmed.charAt(0);
  if (first === '{' || first === '[') return { kind: 'json', ext: '.json', mime: 'application/json' };

  return { kind: 'unknown', ext: '', mime: '' };
}

async function blobToText(blob) {
  // Works in modern browsers
  if (typeof blob.text === 'function') return blob.text();

  // Fallback
  return new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => resolve(String(r.result || ''));
    r.onerror = () => reject(new Error('Failed to read blob as text'));
    r.readAsText(blob);
  });
}

async function blobHeadBytes(blob, n = 64) {
  const slice = blob.slice(0, n);
  const buf = await slice.arrayBuffer();
  return new Uint8Array(buf);
}

/** -----------------------------
 * API: downloadDocument
 * ---------------------------- */

export async function downloadDocument(documentId) {
  if (!documentId) throw new Error('documentId is required');

  // DEV MOCK
  if (!process.env.REACT_APP_API_BASE_URL) {
    const blob = new Blob([`Mock file for ${documentId}`], { type: 'text/plain' });
    return { data: blob, headers: { 'content-type': 'text/plain' } };
  }

  const url = `${API_BASE}/downloadDocument.php`;

  return withAuthRetry(async () => {
    const accessToken = await getAccessToken();
    if (!accessToken) throw new Error('Missing access token');

    console.log('📥 downloadDocument request:', {
      url,
      documentId,
      tokenPrefix: String(accessToken).slice(0, 12) + '...',
    });

    return axios.post(
      url,
      { documentId, accessToken },
      {
        responseType: 'blob', // ✅ keep blob
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'Content-Type': 'application/json',
          Accept: '*/*',
        },
        params: { accessToken },
        validateStatus: (s) => s >= 200 && s < 300,
      }
    );
  });
}

/** -----------------------------
 * Main: download + save with validation
 * ---------------------------- */

export async function downloadAndSaveDocuments(documentId, filenameFromList) {
  const resp = await downloadDocument(documentId);
  const blob = resp?.data;
  console.log('downloadDocument blob:', blob);


  if (!(blob instanceof Blob)) {
    throw new Error('Download failed: response is not a Blob.');
  }

  const contentType =
    resp?.headers?.['content-type'] ||
    resp?.headers?.['Content-Type'] ||
    blob.type ||
    '';

  const contentDisposition =
    resp?.headers?.['content-disposition'] ||
    resp?.headers?.['Content-Disposition'] ||
    '';

  const serverFilename = getFilenameFromContentDisposition(contentDisposition);

  // Read first bytes to detect “JSON/HTML pretending to be DOCX/PDF”
  const head = await blobHeadBytes(blob, 64);
  const sniff = sniffFromBytes(head);

  // If backend returned JSON/HTML, throw a real error (don’t download it)
  if (sniff.kind === 'json' || sniff.kind === 'html') {
    const text = await blobToText(blob);

    // If JSON, try to surface message
    if (sniff.kind === 'json') {
      try {
        const j = JSON.parse(text);
        const msg =
          j?.error || j?.message || j?.Message || j?.detail || JSON.stringify(j);
        throw new Error(`Backend returned JSON instead of a file: ${String(msg).slice(0, 500)}`);
      } catch {
        throw new Error(`Backend returned JSON instead of a file: ${String(text).slice(0, 500)}`);
      }
    }

    throw new Error(`Backend returned HTML instead of a file: ${String(text).slice(0, 500)}`);
  }

  // Determine filename:
  // 1) Content-Disposition filename
  // 2) listDocuments filename
  // 3) fallback
  const baseName = serverFilename || filenameFromList || `document_${documentId}`;

  // If sniff says ZIP and user filename ends in .docx, treat as docx
  const baseExt = extFromFilename(baseName);
  const sniffedExt = sniff.kind === 'zip' && baseExt === '.docx' ? '.docx' : sniff.ext;

  const safeName = ensureExtension(baseName, contentType, sniffedExt);

  console.log('✅ downloadDocument success:', {
    documentId,
    serverFilename,
    listFilename: filenameFromList,
    finalFilename: safeName,
    contentType,
    blobType: blob.type,
    sniffKind: sniff.kind,
    bytes: blob.size,
  });

  // Important: don’t re-wrap blob unless you must.
  // If you do re-wrap, keep type consistent.
  const finalBlob =
    blob.type || !contentType ? blob : new Blob([blob], { type: contentType });

  const url = window.URL.createObjectURL(finalBlob);
  const a = document.createElement('a');
  a.href = url;
  a.download = safeName;
  document.body.appendChild(a);
  a.click();
  a.remove();
  window.URL.revokeObjectURL(url);
}
